#include<bits/stdc++.h>
using namespace std;
int his[25],fac[25]={1},f[25],n,sum;
bool vis[25]={false},flag=false;
void Depth_First_Search(int dep,int s){
	if(dep==n){
		if(s==sum){
			for(int i=0;i<n;i++)cout<<his[i]<<' ';
			cout<<'\n',flag=true;
		}return;
	}
	for(int i=1;i<=n;i++){
		if(vis[i])continue;
		vis[i]=true,his[dep]=i;
		Depth_First_Search(dep+1,s+i*f[dep]);
		vis[i]=false;if(flag)return;
	}
}
int main(void){
	cin>>n>>sum;
	for(int i=1;i<=12;i++)fac[i]=i*fac[i-1];
	for(int i=0;i<n;i++)f[i]=(fac[n-1]/fac[i])/fac[n-1-i];
	Depth_First_Search(0,0);
	return false;
}
